info.is_deleted = 1
AND info.busi_no LIKE CONCAT('%',#{searchVO.busiNo}, '%')
AND info.org_code LIKE CONCAT('%',#{searchVO.orgCode}, '%')
AND info.right_ver = #{searchVO.rightVer}
AND info.app_code IN
#{item}
AND info.busi_id IN
#{item}
AND info.create_user_name LIKE CONCAT('%',#{searchVO.createUser},'%')
AND info.create_time >= #{searchVO.createTimeStart} AND info.create_time <= #{searchVO.createTimeEnd}
AND recycle.recycle_time >= #{searchVO.deleteTimeStart} AND recycle.recycle_time <= #{searchVO.deleteTimeEnd}
ORDER BY recycle.recycle_time DESC

